import React, { lazy, Suspense } from "react";
import { Routes, Route, Navigate, useParams } from "react-router-dom";
import ProtectRouter from "./ProtectRouter";
import PublicRoute from "./PublicRoute";
import GuardRoute from "./GuardRoute";
import { PERMISSIONS } from "../constants/permissions";
import PageLoading from "../components/common/PageLoading";

// Lazy load pages
const EmployeePage = lazy(() => import("../modules/employees/pages/EmployeePage"));
const LoginPage = lazy(() => import("../modules/auth/pages/LoginPage"));
const DepartmentPage = lazy(() => import("../modules/departments/pages/DepartmentPage"));
const AttendancePage = lazy(() => import("../modules/attendance/pages/AttendancePage"));
const OkrPage = lazy(() => import("../modules/okrs/pages/OkrPage"));
const LeaveRequestPage = lazy(() => import("../modules/leave-requests/pages/LeaveRequestPage"));
const PayrollPage = lazy(() => import("../modules/payrolls/pages/PayrollPage"));
const ContractPage = lazy(() => import("../modules/contracts/pages/ContractPage"));
const SchedulePage = lazy(() => import("../modules/schedules/pages/SchedulePage"));
const ShiftTypePage = lazy(() => import("../modules/shifts/pages/ShiftTypePage"));
const DashboardPage = lazy(() => import("../modules/dashboard/pages/DashboardPage"));
const SettingPage = lazy(() => import("../modules/settings/pages/SettingPage"));
const LogPage = lazy(() => import("../modules/logs/pages/LogPage"));
const NikoPage = lazy(() => import("../modules/niko-emotions/pages/NikoPage"));
const AssetPage = lazy(() => import("../pages/PlaceholderPages").then((m) => ({ default: m.AssetPage })));
const EvaluationPage = lazy(() => import("../pages/PlaceholderPages").then((m) => ({ default: m.EvaluationPage })));
const OkrDetailPage = lazy(() => import("../modules/okrs/pages/OkrDetailPage"));
const AccountPage = lazy(() => import("../modules/account/pages/AccountPage"));

import MainLayout from "../components/common/MainLayout";

const OkrRouteDispatcher: React.FC = () => {
  const { slug, cycle } = useParams();
  const param = slug || cycle;
  // Kiểm tra nếu param khớp với mẫu chu kỳ qX-YYYY (ví dụ: q1-2024, q2-2026)
  const isCycle = param?.match(/^q\d-\d{4}$/i);

  if (isCycle) {
    return (
      <GuardRoute permission={PERMISSIONS.OKRS.VIEW_ALL}>
        <OkrPage />
      </GuardRoute>
    );
  }

  return (
    <GuardRoute permission={PERMISSIONS.OKRS.VIEW}>
      <OkrDetailPage />
    </GuardRoute>
  );
};

const AppRouter: React.FC = () => {
  return (
    <Suspense fallback={<PageLoading height="h-screen" tip="Đang tải dữ liệu..." />}>
      <Routes>
        <Route element={<PublicRoute />}>
          <Route path="/login" element={<LoginPage />} />
        </Route>

        {/* Protected Routes */}
        <Route element={<ProtectRouter />}>
          <Route element={<MainLayout />}>
            <Route path="/" element={<DashboardPage />} />
            <Route
              path="/employees"
              element={
                <GuardRoute permission={PERMISSIONS.EMPLOYEES.VIEW_ALL}>
                  <EmployeePage />
                </GuardRoute>
              }
            />
            <Route
              path="/departments"
              element={
                <GuardRoute permission={PERMISSIONS.DEPARTMENTS.VIEW_ALL}>
                  <DepartmentPage />
                </GuardRoute>
              }
            />
            <Route
              path="/attendances"
              element={
                <GuardRoute permission={PERMISSIONS.ATTENDANCES.VIEW_ALL}>
                  <AttendancePage />
                </GuardRoute>
              }
            />
            <Route
              path="/niko"
              element={
                <GuardRoute permission={PERMISSIONS.NIKO_EMOTIONS.VIEW_ALL}>
                  <NikoPage />
                </GuardRoute>
              }
            />
            <Route
              path="/okrs"
              element={
                <GuardRoute permission={PERMISSIONS.OKRS.VIEW_ALL}>
                  <OkrPage />
                </GuardRoute>
              }
            />
            <Route
              path="/okrs/detail/:id"
              element={
                <GuardRoute permission={PERMISSIONS.OKRS.VIEW}>
                  <OkrDetailPage />
                </GuardRoute>
              }
            />
            <Route
              path="/okrs/:slug"
              element={<OkrRouteDispatcher />}
            />
            <Route
              path="/okrs/detail/:employeeId/:quarter/:year"
              element={
                <GuardRoute permission={PERMISSIONS.OKRS.VIEW}>
                  <OkrDetailPage />
                </GuardRoute>
              }
            />
            <Route
              path="/leave-requests"
              element={
                <GuardRoute permission={PERMISSIONS.LEAVE_REQUESTS.VIEW_ALL}>
                  <LeaveRequestPage />
                </GuardRoute>
              }
            />
            <Route
              path="/payrolls"
              element={
                <GuardRoute permission={PERMISSIONS.PAYROLLS.VIEW_ALL}>
                  <PayrollPage />
                </GuardRoute>
              }
            />
            <Route
              path="/contracts"
              element={
                <GuardRoute permission={PERMISSIONS.CONTRACTS.VIEW_ALL}>
                  <ContractPage />
                </GuardRoute>
              }
            />
            <Route
              path="/schedules"
              element={
                <GuardRoute permission={PERMISSIONS.SCHEDULES.VIEW_ALL}>
                  <SchedulePage />
                </GuardRoute>
              }
            />
            <Route
              path="/shift-types"
              element={
                <GuardRoute permission={PERMISSIONS.SHIFTS.VIEW_ALL}>
                  <ShiftTypePage />
                </GuardRoute>
              }
            />
            <Route
              path="/settings"
              element={
                <GuardRoute permission={PERMISSIONS.GLOBAL_SETTINGS.VIEW}>
                  <SettingPage />
                </GuardRoute>
              }
            />
            <Route
              path="/logs"
              element={
                <GuardRoute permission={PERMISSIONS.SYSTEM_LOGS.VIEW_ALL}>
                  <LogPage />
                </GuardRoute>
              }
            />
            <Route path="/assets" element={<AssetPage />} />
            <Route path="/evaluations" element={<EvaluationPage />} />
            <Route path="/account" element={<AccountPage />} />
          </Route>
        </Route>

        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </Suspense>
  );
};

export default AppRouter;
