import { createSlice, type PayloadAction } from "@reduxjs/toolkit";

interface NotificationState {
  pendingLinksCount: number;
  pendingCheckinsCount: number;
  notifications: any[];
}

const initialState: NotificationState = {
  pendingLinksCount: 0,
  pendingCheckinsCount: 0,
  notifications: [],
};

const notificationSlice = createSlice({
  name: "notification",
  initialState,
  reducers: {
    setPendingLinksCount: (state, action: PayloadAction<number>) => {
      state.pendingLinksCount = action.payload;
    },
    incrementPendingLinksCount: (state) => {
      state.pendingLinksCount += 1;
    },
    decrementPendingLinksCount: (state) => {
      state.pendingLinksCount = Math.max(0, state.pendingLinksCount - 1);
    },
    setPendingCheckinsCount: (state, action: PayloadAction<number>) => {
      state.pendingCheckinsCount = action.payload;
    },
    incrementPendingCheckinsCount: (state) => {
      state.pendingCheckinsCount += 1;
    },
    decrementPendingCheckinsCount: (state) => {
      state.pendingCheckinsCount = Math.max(0, state.pendingCheckinsCount - 1);
    },
    addNotification: (state, action: PayloadAction<any>) => {
      state.notifications.unshift(action.payload);
    },
  },
});

export const {
  setPendingLinksCount,
  incrementPendingLinksCount,
  decrementPendingLinksCount,
  setPendingCheckinsCount,
  incrementPendingCheckinsCount,
  decrementPendingCheckinsCount,
  addNotification,
} = notificationSlice.actions;

export default notificationSlice.reducer;

