import React from "react";
import { Navigate, Outlet } from "react-router-dom";
import { useLoginByTokenQuery } from "../modules/auth/services/authApi";
import { useGetPermissionQuery } from "../modules/employees/services/employeeApi";
import PageLoading from "../components/common/PageLoading";

const ProtectRouter: React.FC = () => {
  const token = localStorage.getItem("token");

  // Đợi cả thông tin đăng nhập và danh sách quyền tại đây
  const { isLoading: isAuthLoading, isError: isAuthError } = useLoginByTokenQuery(undefined, {
    skip: !token,
  });

  const { isLoading: isPermLoading } = useGetPermissionQuery(undefined, {
    skip: !token || isAuthError,
  });

  if (!token) {
    return <Navigate to="/login" replace />;
  }

  // Chờ đến khi cả Auth và Permissions đều sẵn sàng
  if (isAuthLoading || isPermLoading) {
    return <PageLoading tip="Đang tải dữ liệu..." height="h-screen" />;
  }

  if (isAuthError) {
    localStorage.removeItem("token");
    return <Navigate to="/login" replace />;
  }

  return <Outlet />;
};

export default ProtectRouter;
