===GuardRoute===
import React, { type ReactNode } from "react";
import { usePermission } from "../hooks/usePermission";
import PermissionDenied from "../components/common/PermissionDenied";

interface GuardRouteProps {
  permission: string | string[];
  children: ReactNode;
}

/**
 * Component bảo vệ cấp độ Trang (Route).
 * Quyền đã được pre-fetch tại ProtectRouter nên ở đây không cần hiện loading nữa.
 */
const GuardRoute: React.FC<GuardRouteProps> = ({ permission, children }) => {
  const { hasPermission, isLoading } = usePermission();

  // Nếu vẫn đang load (hiếm khi xảy ra vì đã đợi ở ProtectRouter), trả về null 
  // để tránh chồng chéo component loading với Suspense.
  if (isLoading) {
    return null;
  }

  if (!hasPermission(permission)) {
    return <PermissionDenied />;
  }

  return <>{children}</>;
};

export default GuardRoute;

