import { useGetPermissionQuery } from "../modules/employees/services/employeeApi";
import { useLoginByTokenQuery } from "../modules/auth/services/authApi";
import { ROLE_CODE } from "../constants/roles";
import { PERMISSIONS } from "../constants/permissions";

export const usePermission = () => {
  const { data: userData } = useLoginByTokenQuery(undefined);
  const { data: permissionData, isLoading } = useGetPermissionQuery(undefined);

  const loginRole = userData?.data?.data?.roles || userData?.data?.roles || userData?.record?.data?.roles;
  const isSuperAdmin = loginRole?.toLowerCase() === ROLE_CODE.SUPER_ADMIN;
  const isAdmin = loginRole?.toLowerCase() === ROLE_CODE.ADMIN;
  const isHR = loginRole?.toLowerCase() === ROLE_CODE.HR;
  const isDirector = loginRole?.toLowerCase() === ROLE_CODE.DIRECTOR;
  const isManager = loginRole?.toLowerCase() === ROLE_CODE.MANAGER;

  const isAdminPrivileged = isAdmin || isSuperAdmin || isHR || isDirector;

  const employeeData = JSON.parse(localStorage.getItem("employee") || "null");
  const currentEmployeeId = employeeData?._id || employeeData;
  const currentDepartmentId = employeeData?.departmentId?._id || employeeData?.departmentId;

  /**
   * Kiểm tra người dùng có quyền hay không
   * @param permission Một permission string hoặc mảng các permission strings
   * @returns boolean
   */
  const hasPermission = (permission: string | string[]): boolean => {
    // Kết quả mới từ /permissions/me là { data: { permissions: string[] } }
    const userPermissions: string[] = permissionData?.data?.permissions || [];

    if (userPermissions.length === 0) return false;

    // Nếu trong danh sách quyền có '*' thì cũng bypass
    if (userPermissions.includes(PERMISSIONS.ALL)) return true;

    // Hàm nội bộ để kiểm tra một permission đơn lẻ (hỗ trợ wildcard module.*)
    const checkSingle = (p: string): boolean => {
      return userPermissions.some((up) => {
        // Khớp hoàn toàn
        if (up === p) return true;
        // Khớp wildcard module (VD: nikoEmotions.* khớp nikoEmotions.view)
        if (up.endsWith(".*")) {
          const modulePrefix = up.slice(0, -1); // "nikoEmotions."
          return p.startsWith(modulePrefix);
        }
        return false;
      });
    };

    if (Array.isArray(permission)) {
      // Trả về true nếu user có ít nhất một trong các quyền truyền vào
      return permission.some((p) => checkSingle(p));
    }

    return checkSingle(permission);
  };

  return {
    hasPermission,
    isLoading,
    isSuperAdmin,
    isAdmin,
    isHR,
    isDirector,
    isManager,
    isAdminPrivileged,
    loginRole,
    userData,
    currentEmployeeId,
    currentDepartmentId,
  };
};
===useDebounce===
import { useEffect, useState } from "react";

/**
 * Hook useDebounce giúp trì hoãn việc cập nhật giá trị cho đến khi sau một khoảng thời gian chờ (delay)
 * tính từ lần cuối cùng giá trị được thay đổi.
 * 
 * @param value Giá trị cần debounce
 * @param delay Khoảng thời gian chờ (ms)
 * @returns Giá trị đã được debounce
 */
export function useDebounce<T>(value: T, delay: number = 500): T {
  const [debouncedValue, setDebouncedValue] = useState<T>(value);

  useEffect(() => {
    // Thiết lập một hẹn giờ để cập nhật giá trị sau khoảng thời gian delay
    const timer = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    // Hủy hẹn giờ nếu giá trị thay đổi trước khi hết thời gian chờ
    return () => {
      clearTimeout(timer);
    };
  }, [value, delay]);

  return debouncedValue;
}

