  UserOutlined,
  TeamOutlined,
  ScheduleOutlined,
} from "@ant-design/icons";
import { useNavigate, Link, useParams } from "react-router-dom";
import { useGetOkrsQuery, useGetOkrObjectivesQuery, useGetKeyResultsQuery } from "../services/okrApi";
import { useGetDepartmentsQuery } from "../../departments/services/departmentApi";
import { useGetEmployeesQuery } from "../../employees/services/employeeApi";
import { useGetGlobalSettingsQuery } from "../../settings/services/settingApi";
import { useGetSchedulesQuery } from "../../checkins/services/checkinApi";
import { trimValues } from "../../../utils/formUtils";
import CycleModal from "../components/CycleModal";
import OkrModal from "../components/OkrModal";
import FilterCard, { FilterItem } from "../../../components/ui/FilterCard";
import { usePermission } from "../../../hooks/usePermission";
import { PERMISSIONS } from "../../../constants/permissions";
import AccessControl from "../../../components/common/AccessControl";
import { generateOkrSlug } from "../../../utils/stringUtils";

/**
 * Hook lấy cross-link employee IDs từ tất cả KRs trong objectives của OKR hiện tại.
 * Dùng currentData thay vì data để tránh stale cache khi đổi quý.
 */
function useCrossLinkPartnerIds(objectives: any[], noOkr: boolean) {
  const objIDs = objectives.slice(0, 10).map((o) => o._id || o.id);

  // RTK Query hooks must be top-level and static
  const { currentData: krs0 } = useGetKeyResultsQuery(objIDs[0], { skip: !objIDs[0] });
  const { currentData: krs1 } = useGetKeyResultsQuery(objIDs[1], { skip: !objIDs[1] });
  const { currentData: krs2 } = useGetKeyResultsQuery(objIDs[2], { skip: !objIDs[2] });
  const { currentData: krs3 } = useGetKeyResultsQuery(objIDs[3], { skip: !objIDs[3] });
  const { currentData: krs4 } = useGetKeyResultsQuery(objIDs[4], { skip: !objIDs[4] });
  const { currentData: krs5 } = useGetKeyResultsQuery(objIDs[5], { skip: !objIDs[5] });
  const { currentData: krs6 } = useGetKeyResultsQuery(objIDs[6], { skip: !objIDs[6] });
  const { currentData: krs7 } = useGetKeyResultsQuery(objIDs[7], { skip: !objIDs[7] });
  const { currentData: krs8 } = useGetKeyResultsQuery(objIDs[8], { skip: !objIDs[8] });
  const { currentData: krs9 } = useGetKeyResultsQuery(objIDs[9], { skip: !objIDs[9] });

  return useMemo(() => {
    if (noOkr) return new Set<string>();
    const ids = new Set<string>();
    const allKrsData = [krs0, krs1, krs2, krs3, krs4, krs5, krs6, krs7, krs8, krs9];
    for (const krsData of allKrsData) {
      for (const kr of krsData?.data || []) {
        for (const link of kr.keyResultLinks || []) {
          const empId = link.employeeId?._id || link.employeeId;
          if (empId) ids.add(String(empId));
        }
      }
    }
    return ids;
  }, [noOkr, krs0, krs1, krs2, krs3, krs4, krs5, krs6, krs7, krs8, krs9]);
}

const { Title, Text } = Typography;

const getProgressColor = (percent: number) => {
  if (percent >= 80) return "#52c41a"; // Xanh lá
  if (percent >= 50) return "#faad14"; // Cam
  return "#ff4d4f"; // Đỏ

