import { baseApi } from "../../../stores/baseApi";
import type { ICheckin, ICheckinPayload, ICheckinSchedule } from "../types";

export const checkinApi = baseApi.injectEndpoints({
  endpoints: (builder) => ({
    getCheckins: builder.query<{ success: boolean; data: ICheckin[] }, string | undefined>({
      query: (employeeId) => (employeeId ? `/checkins?employeeId=${employeeId}` : "/checkins"),
      providesTags: ["Checkins"],
    }),
    createAbnormalCheckin: builder.mutation<{ success: boolean; data: ICheckin }, ICheckinPayload>({
      query: (payload) => ({
        url: "/checkins/abnormal",
        method: "POST",
        body: payload,
      }),
      invalidatesTags: ["Checkins"],
    }),
    updateAbnormalCheckin: builder.mutation<{ success: boolean; data: ICheckin }, { id: string; payload: ICheckinPayload }>({
      query: ({ id, payload }) => ({
        url: `/checkins/abnormal/${id}`,
        method: "PATCH",
        body: payload,
      }),
      invalidatesTags: ["Checkins"],
    }),
    deleteAbnormalCheckin: builder.mutation<{ success: boolean; data: null }, string>({
      query: (id) => ({
        url: `/checkins/abnormal/${id}`,
        method: "DELETE",
      }),
      invalidatesTags: ["Checkins"],
    }),
    confirmCheckin: builder.mutation<{ success: boolean; data: ICheckin }, { id: string; confirmed: boolean }>({
      query: ({ id, confirmed }) => ({
        url: `/checkins/${id}/confirm`,
        method: "POST",
        body: { confirmed },
      }),
      invalidatesTags: ["Checkins"],
    }),
    getSchedules: builder.query<{ success: boolean; data: ICheckinSchedule[] }, string | undefined>({
