import React from "react";
import { Tooltip } from "antd";
import { usePermission } from "../../hooks/usePermission";
import { PERMISSION_MESSAGES } from "../../constants/common";

interface AccessControlProps {
  permission: string | string[];
  children: React.ReactElement;
  message?: string;
}

/**
 * Component bọc ngoài để kiểm soát quyền truy cập thành phần (Button, Link...)
 * Nếu không có quyền, component con sẽ bị disable và hiển thị Tooltip.
 */
const AccessControl: React.FC<AccessControlProps> = ({ 
  permission, 
  children, 
  message = PERMISSION_MESSAGES.ACTION_DENIED_TOOLTIP 
}) => {
  const { hasPermission, isLoading } = usePermission();
  const canAccess = hasPermission(permission);

  // Trong khi loading quyền, tạm thời có thể trả về null hoặc chính con đó nhưng loading
  if (isLoading) return children;

  if (!canAccess) {
    // Clone component con và thêm thuộc tính disabled
    // Áp dụng cho các component hỗ trợ thuộc tính disabled (như Button, Input, v.v. của Antd)
    const childProps = children.props as any;

    return (
      <Tooltip title={message}>
        <span 
          className="cursor-not-allowed" 
          style={{ display: "inline-block", width: childProps.style?.width }}
        >
          {React.cloneElement(children, {
            disabled: true,
            style: { 
              ...childProps.style, 
              opacity: 0.6,
              pointerEvents: "none" 
            },
            onClick: (e: React.MouseEvent) => {
              e.preventDefault();
              e.stopPropagation();
            },
          } as any)}
        </span>
      </Tooltip>
    );
  }

  return children;
};

export default AccessControl;
