import { baseApi } from "../../../stores/baseApi";

export const employeeApi = baseApi.injectEndpoints({
  endpoints: (builder) => ({
    getEmployees: builder.query({
      query: (params) => ({
        url: "/employees",
        params,
      }),
      providesTags: (result) =>
        result?.data
          ? [
              ...result.data.map(({ _id }: any) => ({ type: "Employee" as const, id: _id })),
              { type: "Employee", id: "LIST" },
            ]
          : [{ type: "Employee", id: "LIST" }],
    }),
    getEmployeeDetail: builder.query({
      query: (_id) => `/employees/${_id}`,
      providesTags: (result, error, _id) => [{ type: "Employee", id: _id }],
    }),
    createEmployee: builder.mutation({
      query: (body) => ({
        url: "/employees",
        method: "POST",
        body,
      }),
      invalidatesTags: [{ type: "Employee", id: "LIST" }],
    }),
    updateEmployee: builder.mutation({
      query: ({ _id, ...body }) => ({
        url: `/employees/${_id}`,
        method: "PATCH",
        body,
      }),
      invalidatesTags: (result, error, { _id }) => [
        { type: "Employee", id: _id },
        { type: "Employee", id: "LIST" },
      ],
    }),
    deleteEmployee: builder.mutation({
      query: (id) => ({
        url: `/employees/${id}`,
        method: "DELETE",
      }),
      invalidatesTags: [{ type: "Employee", id: "LIST" }],
    }),
    getPermission: builder.query({
      query: () => "/permissions/me",
      providesTags: ["Auth"],
    }),
  }),
  overrideExisting: false,
});

