  useGetEmployeesQuery,
  useGetEmployeeDetailQuery,
  useCreateEmployeeMutation,
  useUpdateEmployeeMutation,
===NotificationUtils===
import { notification } from "antd";

/**
 * Hiển thị thông báo khi thực hiện các tác vụ CRUD hoặc gặp lỗi từ Backend.
 *
 * Định dạng lỗi từ BE mong đợi:
 * {
 *    "success": false,
 *    "status": 403,
 *    "message": "Nội dung lỗi..."
 * }
 */

export const showNotification = (
  type: "success" | "error" | "info" | "warning",
  message: string,
  description?: string,
) => {
  notification[type]({
    message: message,
    description: description,
    placement: "topRight",
    duration: 4,
  });
};

export const handleError = (error: any, defaultMessage: string = "Đã có lỗi xảy ra") => {
  console.error("API Error:", error);

  let errorMessage = defaultMessage;
  // let errorDescription = "";

  // Xử lý lỗi từ RTK Query (với định dạng BE cung cấp)
  if (error?.data) {
    const data = error.data;
    if (data.message) {
      errorMessage = data.message;
    }
    // if (data.status) {
    //   errorDescription = `Mã lỗi: ${data.status}`;
    // }
  } else if (error?.message) {
    errorMessage = error.message;
  }

  showNotification("error", errorMessage);
  return errorMessage;
};

export const handleSuccess = (message: string, description?: string) => {
  showNotification("success", message, description);
};

