===DebouncedSearchInput===
import React, { useState, useEffect } from "react";
import { Input } from "antd";
import type { InputProps } from "antd";

interface DebouncedSearchInputProps extends Omit<InputProps, "onChange" | "value"> {
  value: string;
  onChange: (value: string) => void;
  debounceTimeout?: number;
}

const DebouncedSearchInput: React.FC<DebouncedSearchInputProps> = ({
  value,
  onChange,
  debounceTimeout = 500,
  ...props
}) => {
  const [localValue, setLocalValue] = useState(value);

  // Cập nhật giá trị local khi value từ prop đổi (ví dụ: khi Reset bộ lọc)
  useEffect(() => {
    setLocalValue(value);
  }, [value]);

  // Cơ chế debounce: Chỉ gọi onChange khi ngừng gõ
  useEffect(() => {
    const timer = setTimeout(() => {
      if (localValue !== value) {
        onChange(localValue);
      }
    }, debounceTimeout);
