const StatusTag: React.FC<StatusTagProps> = ({ status, type = "common" }) => {
  let label = "";
  let color = "";

  switch (type) {
    case "okr": {
      const okr = OKR_STATUS_LABELS[status as string];
      label = okr?.label || (status as string);
      color = okr?.color || "default";
      break;
    }
    case "leave": {
      const leave = LEAVE_STATUS_LABELS[status as string];
      label = leave?.label || (status as string);
      color = leave?.color || "default";
      break;
