import React, { useEffect, useRef } from "react";
import { ConfigProvider, theme } from "antd";
import { useSelector } from "react-redux";
import { useLocation } from "react-router-dom";
import type { RootState } from "../stores/store";

interface AppThemeProviderProps {
  children: React.ReactNode;
}

const AppThemeProvider: React.FC<AppThemeProviderProps> = ({ children }) => {
  const isDarkMode = useSelector((state: RootState) => state.theme.isDarkMode);
  const location = useLocation();
  const isFirstRender = useRef(true);

  // Ép chế độ sáng nếu đang ở trang login
  const isLoginPage = location.pathname === "/login";
  const effectiveIsDarkMode = isLoginPage ? false : isDarkMode;

  useEffect(() => {
    const root = document.documentElement;

    // Chỉ áp dụng no-transition nếu không phải lần render đầu tiên
    if (!isFirstRender.current) {
      root.classList.add("no-transition");
    }

    // Đồng bộ class "dark" dựa trên effectiveIsDarkMode
    if (effectiveIsDarkMode) {
      root.classList.add("dark");
    } else {
      root.classList.remove("dark");
    }

    // Bật lại transitions sau khi DOM đã được cập nhật
    const timeout = setTimeout(() => {
      root.classList.remove("no-transition");
      isFirstRender.current = false;
    }, 100);

    return () => clearTimeout(timeout);
  }, [effectiveIsDarkMode]);

  return (
    <ConfigProvider
      theme={{
        algorithm: effectiveIsDarkMode ? theme.darkAlgorithm : theme.defaultAlgorithm,
        token: {
          colorPrimary: "#0a6ed1",
          borderRadius: 8,
          fontFamily: '"Inter", sans-serif',
          ...(effectiveIsDarkMode && {
            colorBgBase: "#1a1d27",
            colorBgContainer: "#232736",
            colorBgElevated: "#2a2f42",
            colorBgLayout: "#1a1d27",
            colorBorder: "#374151",
            colorBorderSecondary: "#374151",
          }),
        },
      }}
    >
      {children}
    </ConfigProvider>
  );
};

export default AppThemeProvider;
