/**
 * So sánh các giá trị hiện tại của form với giá trị ban đầu và chỉ trả về những trường đã thay đổi.
 * @param values Giá trị hiện tại của form
 * @param initialValues Giá trị ban đầu của bản ghi
 * @returns Đối tượng chứa các trường đã thay đổi, hoặc {} nếu không có thay đổi
 */
export const getChangedValues = (values: any, initialValues: any) => {
  const changedValues: any = {};

  Object.keys(values).forEach((key) => {
    // Chỉ lấy những trường đã định nghĩa trong form
    if (values[key] !== initialValues[key]) {
      // Xử lý trường hợp null vs undefined hoặc số vs chuỗi số nếu cần
      if (values[key] === "" && (initialValues[key] === null || initialValues[key] === undefined)) {
        return;
      }
      changedValues[key] = values[key];
    }
  });

  return changedValues;
};

/**
 * Cắt tỉa khoảng trắng cho tất cả các giá trị kiểu chuỗi trong một đối tượng hoặc mảng.
 * Hỗ trợ đệ quy cho các đối tượng lồng nhau, ngoại trừ các đối tượng đặc biệt như Dayjs.
 * @param values Đối tượng hoặc mảng cần xử lý
 * @returns Đối tượng hoặc mảng đã được làm sạch
 */
export const trimValues = (values: any): any => {
  if (!values || typeof values !== "object") {
    return typeof values === "string" ? values.trim() : values;
  }

  // Tránh đệ quy vào các đối tượng đặc biệt (ví dụ: Dayjs)
  if (values._isAMomentObject || values.$L || values._isDayjsObject || values instanceof Date) {
    return values;
  }

  if (Array.isArray(values)) {
    return values.map((item) => trimValues(item));
  }

  const sanitized: any = {};
  Object.keys(values).forEach((key) => {
    sanitized[key] = trimValues(values[key]);
  });

  return sanitized;
};

